#include <iostream>
#include <string>

struct Plain
{
    int m_value{};
};

struct Polymorphic
{
    int m_value{};
    virtual void f() {}
};

int main()
{
    int n{};
    std::cin >> n;

    std::size_t total{0};
    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;
        std::size_t size{type == "plain" ? sizeof(Plain) : sizeof(Polymorphic)};
        std::cout << type << ": " << size << '\n';
        total += size;
    }

    std::cout << "Total bytes: " << total << '\n';

    return 0;
}

