solution_code:
#include <iostream>
#include <string>
#include <string_view>

class Pipeline
{
public:
    Pipeline()
    {
        std::cout << "Construct stage: " << stage() << '\n';
    }

    virtual ~Pipeline() = default;

    virtual std::string_view stage() const { return "base"; }
};

class FastPipeline : public Pipeline
{
public:
    std::string_view stage() const override { return "fast"; }
};

class SlowPipeline : public Pipeline
{
public:
    std::string_view stage() const override { return "slow"; }
};

int main()
{
    int n{};
    std::cin >> n;

    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;
        Pipeline* p{};
        if (type == "fast")
            p = new FastPipeline{};
        else
            p = new SlowPipeline{};

        std::cout << "Runtime stage: " << p->stage() << '\n';
        delete p;
    }

    return 0;
}
